function toggleTheme(){const t=document.documentElement,i=t.getAttribute("data-bs-theme")||"light",n=i==="light"?"dark":"light";t.setAttribute("data-bs-theme",n);localStorage.setItem("theme",n);document.getElementById("themeIcon").textContent=n==="dark"?"☀️":"🌙"}(function(){const n=localStorage.getItem("theme")||"light";document.documentElement.setAttribute("data-bs-theme",n)})();document.addEventListener("DOMContentLoaded",function(){const t=localStorage.getItem("theme")||"light",n=document.getElementById("themeIcon");n&&(n.textContent=t==="dark"?"☀️":"🌙")});